/// <reference path="../typings/index.d.ts" />
import { libraries, BeSkill, Options} from '@be/be-framework';
import CancelTokenSession = libraries.jibo_cai_utils.CancelTokenSession;
import jibo = require('jibo');

let mainFlow:any = require('./flows/main');

enum FirstContactCloseStatus {
    STOPPED_AND_DESTROYED_FLOW,
    NO_FLOW
}

class FirstContactSkill extends BeSkill {

    public flow:any;
    private hjHandle:jibo.jetstream.HotwordModeToken;

    private _promiseSession:CancelTokenSession = null;
    /**
     * Template skill constructor
     * @constructor
     * @param {String} [assetPack=''] The asset pack if loading from Be
     */
    constructor(assetPack?:Options) {
        super(assetPack);

        this.handleHeadTouch = this.handleHeadTouch.bind(this);
        this._promiseSession = new CancelTokenSession();
    }

    /**
     * Start the skill
     * @method open
     */
    open(result?:any):void {
        this._isInterruptible = false; // nope, sorry
        jibo.action.configure({orientToHJ: false});

        jibo.globalEvents.touchStop.on(this.handleHeadTouch);

        Promise.resolve()
        .then(()=>{
            // cancel any previously running promise session before proceeding
            return this._promiseSession.cancel();
        })
        .then(()=>{
            // turn off attention mode during awakening flow
            return this._promiseSession.wrap(jibo.expression.pushAttentionMode(jibo.expression.AttentionMode.OFF));
        })
        .then((attentionHandler)=>{
            const options = {
                assetPack: this.assetPack,
                blackboard: {
                    numDetected: 0,
                    attentionHandler: attentionHandler,
                    log: this.log
                },
                params: {}
            };

            this.flow = jibo.flow.run(mainFlow, options, () => {
                this._promiseSession.wrap(new Promise((resolve)=>{
                    // redirect to tutorial when we're done!
                    this.redirect('@be/tutorial', {});
                    resolve();
                }));
            });
        })
        .catch((error)=>{
            this.log.warn(error);
            this._promiseSession.wrap(new Promise((resolve)=>{
                // redirect to tutorial when we're done!
                this.redirect('@be/tutorial', {});
                resolve();
            }));

        });
    }

    preload(done:(err?:any)=>void):void {
        this.hjHandle = jibo.jetstream.setHotwordMode(jibo.jetstream.types.HotwordListenMode.Disabled);
        
        this.hjHandle.activated.catch((err)=>{
            //eat error
        }).then(()=>{
            jibo.face.views.forceEyeView(
                ()=>{this._addBlockerView(done);},
                null,
                jibo.face.views.TRANSITION.NONE,
                jibo.face.views.TRANSITION.NONE,
                (err)=>{
                    this.log.error("problem with forcing eye view:", err);
                    this._addBlockerView(done);
                }
            );
        });
    }

    _addBlockerView(done:(err?:any)=>void):void{
        let blockerView = jibo.face.views.createView('View');
        jibo.face.views.changeView(
            {
                addView:blockerView
            },
            ()=>{done();}
        );
    }

    /**
     * Handle the `touchStop` global event.
     * Will eventually be more sophisticated...
     * @method handleHeadTouch
     */
    handleHeadTouch() {
        this.log.info("head touch overriden in first contact");
    }

    /**
     * Stop and unload the skill
     * @method close
     */
    close(done:() => void):void;
    close(done:(error:Error, status:FirstContactCloseStatus) => void):void {
        this._promiseSession.cancel()
        .then(()=>{
            this._clearFC((err?:Error) => {
                if (err) {
                    this.log.warn('Clearing FC: ' + err);
                }

                jibo.globalEvents.touchStop.removeListener(this.handleHeadTouch);
                jibo.action.configure({orientToHJ: true});

                // moving this outside of stopAndDestroy until we get cancellable async setup
                this._isInterruptible = true; // all set

                if (this.hjHandle) {
                    this.hjHandle.release().catch(() => {
                        //eat error
                    }).then(()=>{
                        this.hjHandle = null;
                        if (this.flow) {
                            this.flow.stopAndDestroy().then(()=>{
                                this.flow = null;
                                done(null, FirstContactCloseStatus.STOPPED_AND_DESTROYED_FLOW);
                            });
                        }
                        else {
                            done(null, FirstContactCloseStatus.NO_FLOW);
                        }
                    });
                } else {
                    if (this.flow) {
                        this.flow.stopAndDestroy().then(()=>{
                            this.flow = null;
                            done(null, FirstContactCloseStatus.STOPPED_AND_DESTROYED_FLOW);
                        });
                    }
                    else {
                        done(null, FirstContactCloseStatus.NO_FLOW);
                    }
                }
            });
        });
    }

    _clearFC(done:(error?:Error) => void) : void {
        let kbm = jibo.kb.createModel('/skills-config');
        kbm.loadRoot((err, rootNode)=> {
            if (err) {
                return done(new Error('Unable to load root to set FC flag: ' +err));
            }

            if(rootNode && rootNode.data){
                rootNode.data.hasAlreadyLaunchedFirstContact = true;
                rootNode.save((err)=>{
                    done(err ? new Error('Unable to save FC flag: ' + err) : null);
                });
            }
            else {
                done(new Error("Unable to retrieve root for 'skills-config'"));
            }
        });
    }
}

export = {
    Skill: FirstContactSkill,
    FirstContactSkill: FirstContactSkill,
    FirstContactCloseStatus: FirstContactCloseStatus
};
